module RefModule (  
    input clk,  
    input load,  
    input reset,  
    input [3:0] data,  
    output reg [3:0] q  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset)  
            q <= 4'b0000;  
        else if (load)  
            q <= data;  
        else  
            q <= {q[2:0], 1'b0};  
    end  
endmodule
